// connectorToggleJS adds/removes the checkbox's value from a comma-separated
// signal (con_channels or con_caps) as the admin ticks boxes — the array
// workaround for Datastar's flat signal bag (§6.7).
func connectorToggleJS(signal string) string {
	return "$" + signal + " = el.checked " +
		"? ($" + signal + " ? $" + signal + " + ',' + el.value : el.value) " +
		": $" + signal + ".split(',').filter(function(x){return x && x !== el.value}).join(',')"
}

// joinCSV joins ids into the comma-separated form the edit-seed data attributes
// carry (read back into a signal via el.dataset, dodging the jsString quote
// gotcha).
func joinCSV(ids []string) string {
	out := ""
	for i, s := range ids {
		if i > 0 {
			out += ","
		}
		out += s
	}
	return out
}

func connectorBoolAttr(b bool) string {
	if b {
		return "1"
	}
	return "0"
}

